using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelTests
{
    [TestMethod]
    [DataRow("Smith", "John", "Smith, John", DisplayName = "Standard names")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    [DataRow("Li", "X", "Li, X", DisplayName = "Short names")]
    public void Person_FullName_ReturnsLastCommaFirst(string lastName, string firstName, string expected)
    {
        // Arrange - use Student as concrete subclass of Person
        var person = new Student { LastName = lastName, FirstMidName = firstName };

        // Act
        var result = person.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_TrueWhenSet()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = "abc-123" };

        // Act & Assert
        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null RequestId")]
    [DataRow("", DisplayName = "Empty RequestId")]
    public void ErrorViewModel_ShowRequestId_FalseWhenNullOrEmpty(string? requestId)
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = requestId! };

        // Act & Assert
        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        // Assert
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Instructor_HireDate_CanBeSet()
    {
        // Arrange
        var date = new DateTime(2020, 1, 15);
        var instructor = new Instructor { HireDate = date };

        // Assert
        Assert.AreEqual(date, instructor.HireDate);
    }

    [TestMethod]
    public void Course_Properties_SetCorrectly()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/img.jpg"
        };

        // Assert
        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/uploads/img.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Department_Properties_SetCorrectly()
    {
        // Arrange & Act
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 5
        };

        // Assert
        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.AreEqual(350000m, dept.Budget);
        Assert.AreEqual(new DateTime(2007, 9, 1), dept.StartDate);
        Assert.AreEqual(5, dept.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_Nullable()
    {
        // Arrange
        var dept = new Department { InstructorID = null };

        // Assert
        Assert.IsNull(dept.InstructorID);
    }

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
    public void Enrollment_Grade_CanBeSet(Grade grade)
    {
        // Arrange
        var enrollment = new Enrollment { Grade = grade };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    [TestMethod]
    public void Enrollment_Grade_CanBeNull()
    {
        // Arrange
        var enrollment = new Enrollment { Grade = null };

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    public void Notification_Properties_SetCorrectly()
    {
        // Arrange
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New Student created",
            CreatedAt = now,
            CreatedBy = "System",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("System", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void EntityOperation_HasExpectedValues()
    {
        // Assert
        Assert.AreEqual(0, (int)EntityOperation.CREATE);
        Assert.AreEqual(1, (int)EntityOperation.UPDATE);
        Assert.AreEqual(2, (int)EntityOperation.DELETE);
    }

    [TestMethod]
    public void OfficeAssignment_Properties_SetCorrectly()
    {
        // Arrange & Act
        var office = new OfficeAssignment
        {
            InstructorID = 3,
            Location = "Smith 17"
        };

        // Assert
        Assert.AreEqual(3, office.InstructorID);
        Assert.AreEqual("Smith 17", office.Location);
    }

    [TestMethod]
    public void CourseAssignment_Properties_SetCorrectly()
    {
        // Arrange & Act
        var ca = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 1050
        };

        // Assert
        Assert.AreEqual(1, ca.InstructorID);
        Assert.AreEqual(1050, ca.CourseID);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    private IQueryable<string> CreateSource(int count)
    {
        return Enumerable.Range(1, count).Select(i => $"Item{i}").AsQueryable();
    }

    [TestMethod]
    public void Create_FirstPage_SetsPageIndexToOne()
    {
        // Arrange
        var source = CreateSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsCorrectItemCount()
    {
        // Arrange
        var source = CreateSource(25);

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsFirstItems()
    {
        // Arrange
        var source = CreateSource(25);

