using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    // Note: NotificationService uses a static ConcurrentQueue, so tests that
    // Send/Receive need to drain the queue to avoid cross-test interference.

    private static void DrainQueue(NotificationService svc)
    {
        while (svc.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_GeneratesCreateMessage()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Course", "1050", EntityOperation.CREATE, "System");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 1050) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Department", "3", "Engineering", EntityOperation.UPDATE, "admin");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Instructor", "7", "Jane Smith", EntityOperation.DELETE, "admin");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Instructor 'Jane Smith' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_SetsSystem()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        var result = svc.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleEnqueued_ReturnsFIFO()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);
        svc.SendNotification("A", "1", "First", EntityOperation.CREATE, "user");
        svc.SendNotification("B", "2", "Second", EntityOperation.UPDATE, "user");

        // Act
        var first = svc.ReceiveNotification();
        var second = svc.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.AreEqual("A", first.EntityType);
        Assert.IsNotNull(second);
        Assert.AreEqual("B", second.EntityType);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Arrange
        using var svc = new NotificationService();

        // Act & Assert - no-op implementation should not throw
        svc.MarkAsRead(42);
        svc.MarkAsRead(0);
        svc.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Arrange
        var svc = new NotificationService();

        // Act & Assert - should not throw
        svc.Dispose();
        svc.Dispose();
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);
        var before = DateTime.Now;

        // Act
        svc.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE, "user");

        var after = DateTime.Now;

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdFallback()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Course", "100", null, EntityOperation.UPDATE, "user");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdFallback()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Course", "100", "", EntityOperation.DELETE, "user");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 100) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFallback()
    {
        // Arrange
        using var svc = new NotificationService();
        DrainQueue(svc);

        // Act
        svc.SendNotification("Course", "100", "   ", EntityOperation.CREATE, "user");

        // Assert
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 100) has been created", notification.Message);
    }
}

