        var model = result!.Model as List<EnrollmentDateGroup>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbHelper.CreateContext();
        _controller = new NotificationsController(_context);

        // Drain any leftover notifications from other tests (static queue)
        while (_controller.GetNotifications() is JsonResult jr)
        {
            var value = jr.Value;
            // Use reflection to check count since it's an anonymous type
            var countProp = value?.GetType().GetProperty("count");
            if (countProp != null)
            {
                var count = (int)countProp.GetValue(value)!;
                if (count == 0) break;
            }
            else break;
        }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_NoNotifications_ReturnsSuccessWithEmptyList()
    {
        // Drain any existing notifications
        DrainNotifications();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - drain first, then enqueue
        DrainNotifications();
        var svc = new ContosoUniversity.Services.NotificationService();
        svc.SendNotification("Student", "1", "Test Student", ContosoUniversity.Models.EntityOperation.CREATE, "admin");
        svc.SendNotification("Course", "2", "Test Course", ContosoUniversity.Models.EntityOperation.UPDATE, "admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        var count = (int)countProp.GetValue(value)!;
        Assert.IsTrue(count >= 2, $"Expected at least 2 notifications, got {count}");
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessTrue()
    {
        // Act
        var result = _controller.MarkAsRead(42);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_DifferentIds_AllReturnSuccess()
    {
        // Act & Assert
        foreach (var id in new[] { 0, 1, 100, -1 })
        {
            var result = _controller.MarkAsRead(id);
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));
        }
    }

    private void DrainNotifications()
    {
        // Keep calling GetNotifications until count is 0
        for (int i = 0; i < 100; i++)
        {
            var result = _controller.GetNotifications();
            var value = result.Value;
            if (value == null) break;
            var countProp = value.GetType().GetProperty("count");
            if (countProp == null) break;
            var count = (int)countProp.GetValue(value)!;
            if (count == 0) break;
        }
    }
}

