    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - drain first, then enqueue
        DrainNotifications();
        var svc = new ContosoUniversity.Services.NotificationService();
        svc.SendNotification("Student", "1", "Test Student", ContosoUniversity.Models.EntityOperation.CREATE, "admin");
