using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbHelper.CreateContext();
        TestDbHelper.SeedBasicData(_context);
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    // --- Index tests ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count); // 3 seeded students
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortByNameDesc_ReturnsDescending()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_SortByDateAsc_ReturnsOldestFirst()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName); // 2010
        Assert.AreEqual("Alonso", model[1].LastName); // 2012
        Assert.AreEqual("Anand", model[2].LastName); // 2013
    }

    [TestMethod]
    public void Index_SortByDateDesc_ReturnsNewestFirst()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName); // 2013
        Assert.AreEqual("Alonso", model[1].LastName); // 2012
        Assert.AreEqual("Alexander", model[2].LastName); // 2010
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmpty()
    {
        // Act
        var result = _controller.Index(null, null, "ZZZNotFound", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_SearchString_ResetsPageToOne()
    {
        // Act
        var result = _controller.Index(null, null, "A", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        // Assert — when searchString is provided, page should reset to 1
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilter_PreservedWhenNoSearchString()
    {
        // Act
        _controller.Index(null, "Alexander", null, null);

        // Assert
        Assert.AreEqual("Alexander", _controller.ViewBag.CurrentFilter);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        // Act
        _controller.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_SortOrderNameDesc_TogglesSortParms()
    {
        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert - when current sort is name_desc, next click on Name should be "" (asc)
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_SortOrderDate_TogglesToDateDesc()
    {
        // Act
        _controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    // --- Details tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var studentId = _context.Students.First().ID;

        // Act
        var result = _controller.Details(studentId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(studentId, model.ID);
    }

    // --- Create GET tests ---

    [TestMethod]
    public void Create_GET_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST tests ---

    [TestMethod]
    public void Create_POST_ValidStudent_AddsToDbAndRedirects()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);

        // Verify it was added to the database
        Assert.AreEqual(4, _context.Students.Count()); // 3 seeded + 1 new
    }

    [TestMethod]
    public void Create_POST_MinDateEnrollment_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    [TestMethod]
    public void Create_POST_DateBefore1753_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // --- Edit GET tests ---

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.Edit((int?)student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Edit_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit((int?)99999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Edit POST tests ---

    [TestMethod]
    public void Edit_POST_ValidStudent_UpdatesAndRedirects()
    {
        // Arrange
        var student = _context.Students.First();
        // Detach to avoid tracking conflict
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _controller.Edit(updatedStudent);

        // Assert
        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Edit_POST_MinDateEnrollment_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // --- Delete GET tests ---

    [TestMethod]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.Delete(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Delete_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(99999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed tests ---

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var student = _context.Students.First();
        var initialCount = _context.Students.Count();

        // Act
        var result = _controller.DeleteConfirmed(student.ID);

        // Assert
        var redirect = result as RedirectToActionResult;
        Assert.IsNotNull(redirect);
        Assert.AreEqual("Index", redirect.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Students.Count());
    }
}

