namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbHelper.CreateContext();
        TestDbHelper.SeedBasicData(_context);
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    // --- Index tests ---

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // 2 seeded departments
    }

    [TestMethod]
    public void Index_DepartmentsHaveNames()
    {
        // Act
        var result = _controller.Index() as ViewResult;
        var model = result!.Model as List<Department>;

        // Assert
        Assert.IsNotNull(model);
        var names = model.Select(d => d.Name).OrderBy(n => n).ToList();
        Assert.AreEqual("English", names[0]);
        Assert.AreEqual("Mathematics", names[1]);
    }

    // --- Details tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
